// Shared class recipes. Components compose these instead of re-inventing
// per-component variants. Strings are Tailwind v4 class lists; combine
// with cn() from ../utils.

/** 2px focus ring offset 2px outside the element border. Ring color
 *  reads --primary so it's monochrome ink by default and picks up a
 *  consumer's brand color for free when they override --primary. */
export const focusRing =
  "outline-none focus-visible:outline " +
  "focus-visible:outline-[length:var(--focus-ring-width)] " +
  "focus-visible:outline-[var(--focus-ring-color)] " +
  "focus-visible:outline-offset-[var(--focus-ring-offset)]";

/** Control heights + horizontal padding + icon gap + text recipe.
 *  Single source for sm/md/lg across Button, IconButton, Input, Select
 *  trigger, and any button-shaped primitive. Heights come from
 *  DESIGN.md: sm=24, md=32, lg=40. */
export const controlSize: Record<"sm" | "md" | "lg", string> = {
  sm: "h-6 px-2.5 gap-1.5 text-button-12",  // 24px, button-12
  md: "h-8 px-3.5 gap-2 text-button-14",    // 32px, button-14 (default)
  lg: "h-10 px-4 gap-2 text-button-16",     // 40px, button-16
};

/** State-stepping recipes. Interactive fills walk the surface ladder
 *  or the transparent -> surface-1 -> surface-2 ramp for tertiary
 *  actions; borders walk the three hairline tiers. */
export const stateStepping = {
  /** Solid fill on a card / secondary button. */
  neutralFill:
    "bg-surface-1 hover:bg-surface-2 active:bg-surface-3",
  /** Transparent -> fill ramp for tertiary buttons, menu rows, toolbar
   *  affordances. Reads as ghost until interaction. */
  neutralGhostFill:
    "bg-transparent hover:bg-surface-1 active:bg-surface-2",
  /** 1px hairline that darkens on hover/press. */
  neutralBorder:
    "border border-hairline hover:border-hairline-strong active:border-hairline-tertiary",
};

/** Shared disabled contract. DESIGN.md specifies a flat 50% opacity
 *  with cursor-not-allowed; individual components don't reinvent the
 *  disabled look. */
export const disabled =
  "disabled:opacity-50 disabled:cursor-not-allowed disabled:pointer-events-none";

/** Standard color transition for hover/active fills and borders. */
export const colorTransition =
  "transition-colors duration-[var(--duration-state)] ease-[var(--ease-standard)]";

/** Icons default a step lighter than the label and lift to the label
 *  color on interaction. Applied on the interactive parent element --
 *  the svg inherits via currentColor since lucide icons default to
 *  stroke="currentColor". Class specificity keeps consumer overrides
 *  intact: `<X className="text-error" />` on the svg itself wins over
 *  the arbitrary-selector rules below. */
export const iconMuted =
  "[&_svg]:text-ink-muted [&_svg]:transition-colors [&_svg]:duration-[var(--duration-state)] [&_svg]:ease-[var(--ease-standard)] " +
  "hover:[&_svg]:text-ink focus-visible:[&_svg]:text-ink " +
  "data-[active]:[&_svg]:text-ink data-[popup-open]:[&_svg]:text-ink data-[state=open]:[&_svg]:text-ink data-[state=on]:[&_svg]:text-ink data-highlighted:[&_svg]:text-ink " +
  "aria-pressed:[&_svg]:text-ink aria-selected:[&_svg]:text-ink";

/** Same "muted-at-rest, lift on interaction" idea as iconMuted, but via
 *  opacity so the underlying color (on-primary, error-fg, warning-fg,
 *  etc.) survives. Use on solid-fill variants where changing to
 *  ink-muted would break the fill/text color contract. */
export const iconMutedSolid =
  "[&_svg]:opacity-70 [&_svg]:transition-opacity [&_svg]:duration-[var(--duration-state)] [&_svg]:ease-[var(--ease-standard)] " +
  "hover:[&_svg]:opacity-100 focus-visible:[&_svg]:opacity-100 active:[&_svg]:opacity-100";

/** Popup surface: shared visual chrome for any floating panel that
 *  overlays the canvas -- Menu, Combobox, Select, DatePicker, Tooltip
 *  and friends. Fill uses `--surface-elevated` so it lifts TOWARD white
 *  in light mode (canvas is off-white, popup is pure white) and TOWARD
 *  the palette rung in dark mode. shadow-menu carries the elevation
 *  since our surfaces are otherwise flat. */
export const popupSurface =
  "rounded-[var(--radius-12)] bg-surface-elevated border border-hairline shadow-menu outline-none focus:outline-none";

/** Interactive row inside a popup list (Menu, Combobox, Command,
 *  Select). Density comes as two variants; the base carries the shared
 *  interactive contract (rounded highlight, active fill, disabled).
 *
 *  Usage:
 *    cn(itemRow.base, density === "compact" ? itemRow.compact : itemRow.comfortable, iconMuted, ...)
 */
export const itemRow = {
  base:
    "flex items-center cursor-default select-none rounded-[var(--radius-6)] text-ink outline-none " +
    "data-[active]:bg-surface-2 data-highlighted:bg-surface-2 " +
    "data-[disabled]:pointer-events-none data-[disabled]:opacity-50",
  /** Dense action list. Desktop default in Menu / Combobox. */
  compact: "min-h-7 px-2 py-1.5 text-body-13",
  /** Larger touch targets. Auto-forced on mobile in Menu / Combobox;
   *  also the desktop default in Command palette lists. */
  comfortable: "min-h-9 px-2.5 py-2 text-body-14",
};

/** Section header inside a popup list. Density-aware horizontal padding
 *  so the label's start edge lines up with item text below. */
export const itemGroupLabel = {
  base: "pt-1.5 pb-1 text-caption-11 text-ink-tertiary",
  compact: "px-2",
  comfortable: "px-2.5",
};

/** Full-bleed 1px separator inside a popup list. Assumes the popup's
 *  content wrapper carries `p-1` padding: the `-mx-1` here overshoots
 *  that on both sides so the line reaches the popup's inner border
 *  edge to edge. Used by Menu / Combobox / Command dividers. */
export const popupDivider = "-mx-1 my-1 h-px bg-hairline";
